before.bodyText:
/**
 * Formats a numeric price into a localized currancy string.
 */
export function formatPrice(value: number, currency = 'USD'): string {
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency,
  }).format(value);
}

